/**
 * Service Worker for Push Notifications
 * Generated by VitePWA, with custom push notification handling
 */

// Import push notification handlers
// Use relative path or try multiple paths
try {
  importScripts('/sw-push.js')
} catch (e) {
  try {
    importScripts('/kiosk/sw-push.js')
  } catch (e2) {
    try {
      importScripts('/assets/khanal_tech_integrations/kiosk/sw-push.js')
    } catch (e3) {
      console.error('Failed to load sw-push.js:', e3)
    }
  }
}

// Basic service worker setup
const CACHE_NAME = 'kiosk-cache-v1'
const urlsToCache = [
  '/',
  '/index.html',
  '/icons/icon.svg'
]

// Install event - cache resources
self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME)
      .then((cache) => cache.addAll(urlsToCache))
  )
})

// Activate event - clean up old caches
self.addEventListener('activate', (event) => {
  event.waitUntil(
    caches.keys().then((cacheNames) => {
      return Promise.all(
        cacheNames.map((cacheName) => {
          if (cacheName !== CACHE_NAME) {
            return caches.delete(cacheName)
          }
        })
      )
    })
  )
})

// Fetch event - serve from cache, fallback to network
self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request)
      .then((response) => {
        // Return cached version or fetch from network
        return response || fetch(event.request)
      })
  )
})

